  // Find the nearest common dominator of all scalar values.
  // For non-instruction values (like arguments, constants), treat them as
  // being in the entry block since they're available everywhere.
  BasicBlock *CommonDom = nullptr;
  Function *F = Front->getFunction();
  BasicBlock *EntryBB = &F->getEntryBlock();

